public class VideoData {
    int score;
    private long views;
    private long likes;
    private long sharing;
    private long recentTime;
    private long commmentsCount;
    private long subscribers;

    public VideoData() {
    }

    public int getScore() {
        return score;
    }

    public void setScore(int score) {
        this.score = score;
    }

    public long getViews() {
        return views;
    }

    public void setViews(long views) {
        this.views = views;
    }

    public long getLikes() {
        return likes;
    }

    public void setLikes(long likes) {
        this.likes = likes;
    }

    public long getSharing() {
        return sharing;
    }

    public void setSharing(long sharing) {
        this.sharing = sharing;
    }

    public long getRecentTime() {
        return recentTime;
    }

    public void setRecentTime(long recentTime) {
        this.recentTime = recentTime;
    }

    public long getCommmentsCount() {
        return commmentsCount;
    }

    public void setCommmentsCount(long commmentsCount) {
        this.commmentsCount = commmentsCount;
    }

    public long getSubscribers() {
        return subscribers;
    }

    public void setSubscribers(long subscribers) {
        this.subscribers = subscribers;
    }
}

public class ViralScoreCalculator {

    private static final double MAX_RECENCY_DECAY = 0.05;

    private static final double WEIGHT_VIEWS = 1.0;
    private static final double WEIGHT_LIKES = 1.5;
    private static final double WEIGHT_COMMENTS = 2.5;
    private static final double WEIGHT_SHARES = 4.0;

    public double calculate(VideoData videoData) {
        double baseScore = calculateEngagementScore(videoData);
        double recencyMultiplier = calculateRecencyMultiplier(videoData.getRecentTime());
        return baseScore * recencyMultiplier;
    }

    private double calculateEngagementScore(VideoData videoData) {
        double logViews = Math.log1p(videoData.getViews());
        double logLikes = Math.log1p(videoData.getLikes());
        double logComments = Math.log1p(videoData.getCommmentsCount());
        double logShares = Math.log1p(videoData.getSharing());

        double weightedScore =
                WEIGHT_VIEWS * logViews +
                WEIGHT_LIKES * logLikes +
                WEIGHT_COMMENTS * logComments +
                WEIGHT_SHARES * logShares;

        long views = Math.max(videoData.getViews(), 1);
        double shareRate = (double) videoData.getSharing() / views;
        double commentRate = (double) videoData.getCommmentsCount() / views;
        double qualityBoost = 1.0 + (2.0 * shareRate) + (1.0 * commentRate);

        return weightedScore * qualityBoost;
    }

    /**
     * Recency decay is capped at 5% — engagement metrics dominate, especially on older posts.
     * Fresh content: multiplier = 1.0
     * Fully aged content: multiplier = 0.95 (at most 5% reduction)
     */
    private double calculateRecencyMultiplier(long recentTimeMillis) {
        long now = System.currentTimeMillis();
        long ageHours = Math.max(0, (now - recentTimeMillis) / (1000 * 60 * 60));

        // 0 = just updated, approaches 1 as the post ages (~72h half-life toward full decay)
        double ageFactor = 1.0 - Math.exp(-ageHours / 72.0);
        double decay = MAX_RECENCY_DECAY * ageFactor;

        return 1.0 - decay;
    }
}

public class ViralVideos {
    String userID;
    String contentID;
    String contentLink;
    double score;

    public ViralVideos() {
    }

    public ViralVideos(String userID, String contentID, String contentLink) {
        this.userID = userID;
        this.contentID = contentID;
        this.contentLink = contentLink;
    }

    public double getScore() {
        return score;
    }

    public void setScore(double score) {
        this.score = score;
    }
}

